// Each input item is one repo. Add a 'group' field by splitting name on '-'.
// Custom groups override.
const customGroups = {
  'data-get': 'data',
  'kaos': 'kaos',
  'greenfin-uz': 'greenfin',
  'dissertation-reestr': 'dissertation',
  'devops-agent': 'devops',
};
const exclude = new Set([]);

const out = [];
for (const item of $input.all()) {
  const r = item.json;
  if (exclude.has(r.name)) continue;
  const group = customGroups[r.name] || r.name.split('-')[0];
  out.push({ json: {
    name: r.name,
    full_name: r.full_name,
    group,
    pushed_at: r.pushed_at,
    private: r.private,
    default_branch: r.default_branch || 'main',
    description: r.description,
  }});
}
return out;

// Add 'since_24h' to every repo item — used in subsequent API calls.
const since = new Date(Date.now() - 24 <b> 3600 </b> 1000).toISOString();
return $input.all().map(it => ({ json: { ...it.json, since_24h: since } }));

// Walk through pairs of items from 4 parallel branches by index.
// In n8n, the 'index' aligns when the same repo went through all 4 calls.
const since = new Date(Date.now() - 24 <b> 3600 </b> 1000);

const commitsItems = $('Get commits').all();
const prsItems = $('Get PRs').all();
const issuesItems = $('Get issues').all();
const runsItems = $('Get CI runs').all();
const metaItems = $('Compute Since').all();

const projects = {};

for (let i = 0; i < metaItems.length; i++) {
  const meta = metaItems[i].json;
  const repo = meta.name;
  const group = meta.group;

  const commits = Array.isArray(commitsItems[i]?.json) ? commitsItems[i].json : [];
  const prs = Array.isArray(prsItems[i]?.json) ? prsItems[i].json : [];
  const issues = Array.isArray(issuesItems[i]?.json) ? issuesItems[i].json : [];
  const runsObj = runsItems[i]?.json || {};
  const runs = runsObj.workflow_runs || [];

  const recentPrs = prs.filter(p => new Date(p.updated_at) >= since);
  const openPrs = prs.filter(p => p.state === 'open');
  const mergedToday = recentPrs.filter(p => p.merged_at && new Date(p.merged_at) >= since);
  const closedToday = recentPrs.filter(p => p.state === 'closed' && !p.merged_at);

  const newIssues = issues.filter(i => !i.pull_request && new Date(i.created_at) >= since);
  const closedIssues = issues.filter(i => !i.pull_request && i.state === 'closed' && i.closed_at && new Date(i.closed_at) >= since);

  const lastFailed = runs.find(r => r.conclusion === 'failure' && new Date(r.created_at) >= since);

  projects[group] = projects[group] || {
    group, repos: [], totalCommits: 0, totalContribs: {}, openPrs: 0,
    mergedToday: 0, closedToday: 0, newIssues: 0, closedIssues: 0,
    failedCi: [],
  };
  const p = projects[group];
  p.repos.push({
    name: repo,
    commits: commits.length,
    samples: commits.slice(0, 3).map(c => (c.commit?.message || '').split('\n')[0]),
    private: meta.private,
  });
  p.totalCommits += commits.length;
  for (const c of commits) {
    const a = c.author?.login || c.commit?.author?.name || '?';
    p.totalContribs[a] = (p.totalContribs[a] || 0) + 1;
  }
  p.openPrs += openPrs.length;
  p.mergedToday += mergedToday.length;
  p.closedToday += closedToday.length;
  p.newIssues += newIssues.length;
  p.closedIssues += closedIssues.length;
  if (lastFailed) p.failedCi.push({ repo, name: lastFailed.name, html_url: lastFailed.html_url });
}

// Build markdown digest
const date = new Date().toLocaleDateString('uz-UZ', { day:'2-digit', month:'long', year:'numeric' });
let msg = <code>📊 <b>GitHub kunlik hisobot</b>\n${date}\n${'─'.repeat(20)}\n</code>;

const groupNames = Object.keys(projects).sort();
let totalCommits = 0, totalProjects = 0;
for (const g of groupNames) {
  const p = projects[g];
  if (p.totalCommits === 0 && p.openPrs === 0 && p.mergedToday === 0 && p.newIssues === 0) continue;
  totalProjects++;
  totalCommits += p.totalCommits;
  msg += <code>\n🏗 <b>${g}</b> (${p.repos.length} repo)\n</code>;
  msg += <code>   📈 ${p.totalCommits} commit · ${p.mergedToday} PR merged · ${p.openPrs} ochiq PR · ${p.newIssues} yangi issue\n</code>;
  const top = Object.entries(p.totalContribs).sort((a,b)=>b[1]-a[1]).slice(0,3);
  if (top.length) msg += <code>   🔥 Faol: ${top.map(([u,n])=></code>@${u} (${n})<code>).join(', ')}\n</code>;
  for (const r of p.repos) {
    if (r.commits === 0) continue;
    const samples = r.samples.map(s => <code>"${s.slice(0, 60)}"</code>).join(', ');
    msg += <code>   • \</code>${r.name}\<code> — ${r.commits} commit · ${samples}\n</code>;
  }
  if (p.failedCi.length) {
    msg += <code>   ⚠️ CI fail: ${p.failedCi.map(f => </code>${f.repo}/${f.name}<code>).join(', ')}\n</code>;
  }
}

if (totalCommits === 0) msg += <code>\n⏸ Kechagi 24 soatda faollik yo'q.</code>;
else msg += <code>\n${'─'.repeat(20)}\n📅 Jami: ${totalCommits} commit · ${totalProjects} ta loyiha</code>;

return [{ json: { message: msg } }];
